// ============================================================
// THEME TOGGLE
// ============================================================
(function () {
  const t = document.querySelector('[data-theme-toggle]'),
    r = document.documentElement;
  let d = matchMedia('(prefers-color-scheme:dark)').matches ? 'dark' : 'light';
  r.setAttribute('data-theme', d);
  t &&
    t.addEventListener('click', () => {
      d = d === 'dark' ? 'light' : 'dark';
      r.setAttribute('data-theme', d);
      t.setAttribute('aria-label', 'Switch to ' + (d === 'dark' ? 'light' : 'dark') + ' mode');
      t.innerHTML =
        d === 'dark'
          ? '<svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><circle cx="12" cy="12" r="5"/><path d="M12 1v2M12 21v2M4.22 4.22l1.42 1.42M18.36 18.36l1.42 1.42M1 12h2M21 12h2M4.22 19.78l1.42-1.42M18.36 5.64l1.42-1.42"/></svg>'
          : '<svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M21 12.79A9 9 0 1 1 11.21 3 7 7 0 0 0 21 12.79z"/></svg>';
    });
})();

// ============================================================
// INTERACTIVE MAP
// ============================================================
(function () {
  const CATEGORY_COLORS = {
    STRUT: '#c77b2e',
    FEED: '#3d6b35',
    BORDER: '#a12c3e',
    WATER: '#2a7a8a',
    ROOST: '#6b3a6b',
    LISTEN: '#5a5a5a',
  };

  // Initialize map
  const map = L.map('mapContainer', {
    center: [30.15, -84.45],
    zoom: 9,
    zoomControl: true,
    preferCanvas: true,
  });

  // Tile layers
  const osmLayer = L.tileLayer('https://tile.openstreetmap.org/{z}/{x}/{y}.png', {
    maxZoom: 19,
    attribution: '&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a>',
  });

  const topoLayer = L.tileLayer('https://{s}.tile.opentopomap.org/{z}/{x}/{y}.png', {
    maxZoom: 17,
    attribution: '&copy; <a href="https://opentopomap.org">OpenTopoMap</a>',
  });

  const satLayer = L.tileLayer('https://server.arcgisonline.com/ArcGIS/rest/services/World_Imagery/MapServer/tile/{z}/{y}/{x}', {
    maxZoom: 19,
    attribution: '&copy; Esri',
  });

  osmLayer.addTo(map);

  L.control.layers({
    'Street': osmLayer,
    'Topographic': topoLayer,
    'Satellite': satLayer,
  }, null, { position: 'topright' }).addTo(map);

  // Create marker clusters per category
  const clusterGroups = {};
  const allMarkers = [];

  Object.keys(CATEGORY_COLORS).forEach((cat) => {
    clusterGroups[cat] = L.markerClusterGroup({
      maxClusterRadius: 40,
      iconCreateFunction: function (cluster) {
        const count = cluster.getChildCount();
        return L.divIcon({
          html: '<div style="background:' + CATEGORY_COLORS[cat] + ';color:#fff;border-radius:50%;width:32px;height:32px;display:flex;align-items:center;justify-content:center;font-size:12px;font-weight:700;box-shadow:0 2px 6px rgba(0,0,0,0.3);">' + count + '</div>',
          className: '',
          iconSize: [32, 32],
        });
      },
    });
  });

  // Parse desc fields for popup
  function parseDesc(desc) {
    const fields = {};
    const pairs = desc.split(' | ');
    pairs.forEach((pair) => {
      const colonIdx = pair.indexOf(':');
      if (colonIdx > -1) {
        const key = pair.substring(0, colonIdx).trim();
        const val = pair.substring(colonIdx + 1).trim();
        fields[key] = val;
      }
    });
    return fields;
  }

  // Add waypoints
  WAYPOINTS.forEach((wp) => {
    const color = CATEGORY_COLORS[wp.category] || '#888';
    const size = Math.max(8, Math.min(14, (wp.score - 85) * 0.3 + 8));

    const icon = L.divIcon({
      html: '<div style="background:' + color + ';width:' + size + 'px;height:' + size + 'px;border-radius:50%;border:2px solid #fff;box-shadow:0 1px 4px rgba(0,0,0,0.3);"></div>',
      className: '',
      iconSize: [size, size],
      iconAnchor: [size / 2, size / 2],
    });

    const fields = parseDesc(wp.desc);

    let popupHtml = '<div class="popup-title" style="color:' + color + '">' + wp.name + '</div>';
    popupHtml += '<div class="popup-score">' + (fields['Score'] || 'Score: ' + wp.score) + '</div>';
    popupHtml += '<hr style="border:none;border-top:1px solid #eee;margin:6px 0">';

    // Key details
    const detailKeys = ['Water', 'Edge density', 'Elevation adv', 'Cover diversity', 'Clearing', 'Timber', 'Road dist'];
    detailKeys.forEach((key) => {
      if (fields[key]) {
        let val = fields[key];
        // Shorten numeric values
        const numMatch = val.match(/^(\d+\.\d{1,2})/);
        if (numMatch) val = numMatch[1] + val.replace(numMatch[1], '').replace(/^\d*/, '');
        popupHtml += '<div class="popup-detail"><span class="label">' + key + '</span><span class="value">' + val + '</span></div>';
      }
    });

    popupHtml += '<hr style="border:none;border-top:1px solid #eee;margin:6px 0">';
    popupHtml += '<div class="popup-detail"><span class="label">Land</span><span class="value">' + wp.land + '</span></div>';
    popupHtml += '<div class="popup-detail"><span class="label">County</span><span class="value">' + wp.county + '</span></div>';

    if (fields['Permit']) {
      popupHtml += '<div style="margin-top:6px;font-size:11px;color:#6b6758;background:#f5f2ec;padding:4px 8px;border-radius:4px;">' + fields['Permit'] + '</div>';
    }

    if (fields['Border advantage']) {
      popupHtml += '<div style="margin-top:4px;font-size:11px;color:#a12c3e;font-weight:600;">' + fields['Border advantage'] + '</div>';
    }

    const marker = L.marker([wp.lat, wp.lon], { icon: icon })
      .bindPopup(popupHtml, { maxWidth: 280 });

    marker._wpCategory = wp.category;

    if (clusterGroups[wp.category]) {
      clusterGroups[wp.category].addLayer(marker);
    }

    allMarkers.push(marker);
  });

  // Add all cluster groups to map
  Object.values(clusterGroups).forEach((g) => map.addLayer(g));

  // Filter buttons
  let activeFilter = 'all';

  document.querySelectorAll('.filter-btn').forEach((btn) => {
    btn.addEventListener('click', function () {
      const filter = this.getAttribute('data-filter');

      document.querySelectorAll('.filter-btn').forEach((b) => b.classList.remove('active'));
      this.classList.add('active');

      activeFilter = filter;

      Object.entries(clusterGroups).forEach(([cat, group]) => {
        if (filter === 'all' || filter === cat) {
          if (!map.hasLayer(group)) map.addLayer(group);
        } else {
          if (map.hasLayer(group)) map.removeLayer(group);
        }
      });
    });
  });
})();

// ============================================================
// SCROLL ANIMATIONS
// ============================================================
(function () {
  const sections = document.querySelectorAll('.guide-section');
  const observer = new IntersectionObserver(
    (entries) => {
      entries.forEach((entry) => {
        if (entry.isIntersecting) {
          entry.target.classList.add('visible');
        }
      });
    },
    { threshold: 0.05, rootMargin: '0px 0px -50px 0px' }
  );
  sections.forEach((s) => observer.observe(s));
})();

// ============================================================
// BACK TO TOP
// ============================================================
(function () {
  const btn = document.getElementById('backToTop');
  window.addEventListener('scroll', () => {
    btn.classList.toggle('visible', window.scrollY > 600);
  });
  btn.addEventListener('click', () => {
    window.scrollTo({ top: 0, behavior: 'smooth' });
  });
})();

// ============================================================
// TOC ACTIVE STATE
// ============================================================
(function () {
  const tocLinks = document.querySelectorAll('.toc-sidebar a');
  if (!tocLinks.length) return;

  const sections = [];
  tocLinks.forEach((link) => {
    const id = link.getAttribute('href').replace('#', '');
    const el = document.getElementById(id);
    if (el) sections.push({ link, el });
  });

  function updateActive() {
    let current = sections[0];
    const scrollY = window.scrollY + 120;
    sections.forEach((s) => {
      if (s.el.offsetTop <= scrollY) current = s;
    });
    tocLinks.forEach((l) => l.classList.remove('active'));
    if (current) current.link.classList.add('active');
  }

  window.addEventListener('scroll', updateActive, { passive: true });
  updateActive();
})();
